	(100, '[{"columnname":"Exploitation","datatype":"text","dvquerytext":"Select name as id, name as idval FROM exploitation WHERE expl_id > 0 ORDER BY name","isNullValue":"true","label":"Exploitation:","layoutorder":1,"widgettype":"combo"},{"columnname":"Arc Catalog","datatype":"text","dvquerytext":"Select id as id, id as idval FROM cat_arc WHERE id IS NOT NULL ORDER BY id","isNullValue":"true","label":"Arc catalog:","layoutorder":2,"widgettype":"combo"}]'),
